import { CalendarDays } from "lucide-react";
import { useTranslation } from "react-i18next";
import BookingDialog from "./BookingDialog";

interface BookingButtonProps {
  restaurantId: string;
  restaurantName: string;
  className?: string;
}

const BookingButton = ({ restaurantId, restaurantName, className }: BookingButtonProps) => {
  const { t } = useTranslation();

  return (
    <BookingDialog
      restaurantId={restaurantId}
      restaurantName={restaurantName}
      trigger={
        <button
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium
            bg-primary/90 text-primary-foreground hover:bg-primary shadow-md
            backdrop-blur-sm transition-all duration-200 active:scale-95 ${className || ""}`}
        >
          <CalendarDays className="w-3.5 h-3.5" />
          <span>{t("booking.button", "订台")}</span>
        </button>
      }
    />
  );
};

export default BookingButton;
