import { useState } from "react";
import { Languages, Loader2, Heart, HandPlatter } from "lucide-react";
import { useTranslation } from "react-i18next";
import { ChefDishShowcaseCard } from "@/components/chef/ChefDishShowcaseCard";

export interface SignatureDish {
  id: string;
  dish_name_zh: string;
  dish_name_en: string | null;
  dish_name_pt: string | null;
  description_zh: string | null;
  description_en: string | null;
  description_pt: string | null;
  neijing_zh: string | null;
  neijing_en: string | null;
  neijing_pt: string | null;
  image_url: string | null;
  sort_order: number | null;
  likes_count: number;
  wants_count: number;
}

interface SignatureDishListProps {
  dishes: SignatureDish[];
  currentLang: string;
  expandedDish: string | null;
  setExpandedDish: (id: string | null) => void;
  neijingTranslations: Record<string, { text: string; showTranslated: boolean }>;
  translatingDishId: string | null;
  /** Dish content translations (name + description) */
  dishContentTranslations: Record<string, { name?: string; description?: string; show: boolean }>;
  translatingDishContentId: string | null;
  currentUserLikes: Set<string>;
  currentUserWants: Set<string>;
  onLike: (dishId: string) => void;
  onWant: (dishId: string) => void;
  onTranslateNeijing: (dish: SignatureDish) => void;
  onTranslateDishContent: (dish: SignatureDish) => void;
}

export const SignatureDishList = ({
  dishes,
  currentLang,
  expandedDish,
  setExpandedDish,
  neijingTranslations,
  translatingDishId,
  dishContentTranslations,
  translatingDishContentId,
  currentUserLikes,
  currentUserWants,
  onLike,
  onWant,
  onTranslateNeijing,
  onTranslateDishContent,
}: SignatureDishListProps) => {
  const { t } = useTranslation();
  const [previewImage, setPreviewImage] = useState<{ src: string; alt: string } | null>(null);

  // Always return original (ZH) text for dish content; neijing always ZH
  const getOriginalField = (dish: SignatureDish, field: "dish_name" | "description" | "neijing") => {
    if (field === "neijing") {
      return dish.neijing_zh || "";
    }
    return (dish[`${field}_zh` as keyof SignatureDish] as string) || "";
  };

  if (dishes.length === 0) return null;

  return (
    <div>
      <div className="mb-5 text-center md:mb-7">
        <p className="mb-1 text-[10px] font-medium uppercase tracking-[0.18em] text-primary md:text-xs">
          {t("chef.signatureDishes", "招牌菜品")}
        </p>
        <h2 className="text-xl font-bold tracking-tight text-foreground md:text-2xl">
          {t("chef.signatureDishes", "招牌菜品")}
        </h2>
        <p className="mt-1 text-xs text-muted-foreground md:text-sm">
          {t("chef.healthReading", "每道菜品附《黄帝内经》养生解读")}
        </p>
      </div>

      <div className="mx-auto flex max-w-4xl flex-col gap-4">
        {dishes.map((dish, index) => {
          const rawDishName = getOriginalField(dish, "dish_name");
          const rawDescription = getOriginalField(dish, "description");
          const neijing = getOriginalField(dish, "neijing");
          const neijingState = neijingTranslations[dish.id];
          const displayNeijing = neijingState?.showTranslated ? neijingState.text : neijing;
          const isTranslatingNeijing = translatingDishId === dish.id;

          // Dish content translation state
          const dishContentState = dishContentTranslations[dish.id];
          const isTranslatingDishContent = translatingDishContentId === dish.id;
          const showDishTranslated = !!dishContentState?.show;
          const dishName = showDishTranslated && dishContentState?.name ? dishContentState.name : rawDishName;
          const description = showDishTranslated && dishContentState?.description ? dishContentState.description : rawDescription;

          const isExpanded = expandedDish === dish.id;

          const dishTranslateLabel = isTranslatingDishContent
            ? t("translate.translating", "翻译中...")
            : showDishTranslated
              ? t("translate.showOriginal", "显示原文")
              : t("translate.button", "翻译");

          const neijingTranslateLabel = isTranslatingNeijing
            ? t("translate.translating", "翻译中...")
            : neijingState?.showTranslated
              ? t("translate.showOriginal", "显示原文")
              : t("translate.button", "翻译");

          return (
            <ChefDishShowcaseCard
              key={dish.id}
              badgeLabel={t("chef.signatureDishes", "招牌菜品")}
              badgeIndex={index + 1}
              title={dishName}
              summary={description}
              imageUrl={dish.image_url}
              imageAlt={dishName}
              expanded={isExpanded}
              onToggleExpanded={() => setExpandedDish(isExpanded ? null : dish.id)}
              detailLabel={t("chef.dishDescription", "菜品介绍")}
              detailText={description}
              insightLabel={t("chef.neijingInterpretation", "《黄帝内经》解读")}
              insightText={displayNeijing}


              previewImage={previewImage}
              setPreviewImage={setPreviewImage}
              clickToPreview={t("chef.clickToPreview", "点击放大预览")}
              footer={
                <div className="flex items-center gap-2">
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onWant(dish.id);
                    }}
                    className={`inline-flex items-center gap-1 rounded-full px-2.5 py-1 text-[11px] transition-colors ${
                      currentUserWants.has(dish.id)
                        ? "bg-primary/10 text-primary"
                        : "bg-muted/70 text-muted-foreground hover:text-primary"
                    }`}
                    title={t("chef.wantToEat", "想吃")}
                  >
                    <HandPlatter className={`h-3.5 w-3.5 ${currentUserWants.has(dish.id) ? "fill-current" : ""}`} />
                    <span>{dish.wants_count || 0}</span>
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onLike(dish.id);
                    }}
                    className={`inline-flex items-center gap-1 rounded-full px-2.5 py-1 text-[11px] transition-colors ${
                      currentUserLikes.has(dish.id)
                        ? "bg-destructive/10 text-destructive"
                        : "bg-muted/70 text-muted-foreground hover:text-destructive"
                    }`}
                  >
                    <Heart className={`h-3.5 w-3.5 ${currentUserLikes.has(dish.id) ? "fill-current" : ""}`} />
                    <span>{dish.likes_count || 0}</span>
                  </button>
                </div>
              }
            />
          );
        })}
      </div>
    </div>
  );
};
