import { useState } from "react";
import { useTranslation } from "react-i18next";
import { CalendarDays, Clock, Users, User, Phone, Mail, MessageSquare, Loader2, CheckCircle2 } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { format, addDays } from "date-fns";

interface BookingDialogProps {
  restaurantId: string;
  restaurantName: string;
  trigger: React.ReactNode;
}

const TIME_SLOTS = [
  "11:30", "12:00", "12:30", "13:00", "13:30",
  "18:00", "18:30", "19:00", "19:30", "20:00", "20:30", "21:00",
];

const PARTY_SIZES = [1, 2, 3, 4, 5, 6, 7, 8, 10, 12];

const BookingDialog = ({ restaurantId, restaurantName, trigger }: BookingDialogProps) => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [open, setOpen] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);

  const [guestName, setGuestName] = useState("");
  const [guestPhone, setGuestPhone] = useState("");
  const [guestEmail, setGuestEmail] = useState("");
  const [partySize, setPartySize] = useState("2");
  const [bookingDate, setBookingDate] = useState("");
  const [bookingTime, setBookingTime] = useState("");
  const [specialRequests, setSpecialRequests] = useState("");

  // Generate next 30 days for date options
  const dateOptions = Array.from({ length: 30 }, (_, i) => {
    const date = addDays(new Date(), i + 1);
    return {
      value: format(date, "yyyy-MM-dd"),
      label: format(date, "MM/dd (EEE)"),
    };
  });

  const resetForm = () => {
    setGuestName("");
    setGuestPhone("");
    setGuestEmail("");
    setPartySize("2");
    setBookingDate("");
    setBookingTime("");
    setSpecialRequests("");
    setSuccess(false);
  };

  const handleSubmit = async () => {
    if (!user) {
      toast.error(t("common.loginRequired", "请先登录"));
      return;
    }
    if (!guestName.trim()) {
      toast.error(t("booking.form.nameRequired", "请输入姓名"));
      return;
    }
    if (!bookingDate) {
      toast.error(t("booking.form.dateRequired", "请选择日期"));
      return;
    }
    if (!bookingTime) {
      toast.error(t("booking.form.timeRequired", "请选择时间"));
      return;
    }

    setSubmitting(true);
    try {
      const { error } = await supabase.from("restaurant_bookings" as any).insert({
        restaurant_id: restaurantId,
        user_id: user.id,
        guest_name: guestName.trim(),
        guest_phone: guestPhone.trim() || null,
        guest_email: guestEmail.trim() || null,
        party_size: parseInt(partySize),
        booking_date: bookingDate,
        booking_time: bookingTime,
        special_requests: specialRequests.trim() || null,
        status: "pending",
      });

      if (error) throw error;

      setSuccess(true);
      toast.success(t("booking.form.success", "预订成功！"));
    } catch (err) {
      console.error("Booking error:", err);
      toast.error(t("booking.form.error", "预订失败，请稍后重试"));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) setTimeout(resetForm, 300); }}>
      <DialogTrigger asChild>
        {trigger}
      </DialogTrigger>
      <DialogContent className="sm:max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-lg">
            <CalendarDays className="w-5 h-5 text-primary" />
            {t("booking.form.title", "预订餐位")}
          </DialogTitle>
          <p className="text-sm text-muted-foreground mt-1">{restaurantName}</p>
        </DialogHeader>

        {success ? (
          <div className="flex flex-col items-center gap-4 py-8">
            <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center">
              <CheckCircle2 className="w-8 h-8 text-primary" />
            </div>
            <div className="text-center space-y-2">
              <h3 className="text-lg font-semibold">{t("booking.form.successTitle", "预订已提交！")}</h3>
              <p className="text-sm text-muted-foreground max-w-xs">
                {t("booking.form.successDesc", "我们已收到您的预订请求，餐厅确认后将通知您。")}
              </p>
            </div>
            <div className="bg-muted/50 rounded-xl p-4 w-full space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">{t("booking.form.date", "日期")}</span>
                <span className="font-medium">{bookingDate}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">{t("booking.form.time", "时间")}</span>
                <span className="font-medium">{bookingTime}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">{t("booking.form.partySize", "人数")}</span>
                <span className="font-medium">{partySize} {t("booking.people", "人")}</span>
              </div>
            </div>
            <Button onClick={() => setOpen(false)} className="mt-2 w-full">
              {t("common.close", "关闭")}
            </Button>
          </div>
        ) : (
          <div className="space-y-4 pt-2">
            {/* Guest Name */}
            <div className="space-y-1.5">
              <Label className="text-sm font-medium flex items-center gap-1.5">
                <User className="w-3.5 h-3.5" />
                {t("booking.form.guestName", "姓名")} *
              </Label>
              <Input
                value={guestName}
                onChange={(e) => setGuestName(e.target.value)}
                placeholder={t("booking.form.guestNamePlaceholder", "请输入您的姓名")}
              />
            </div>

            {/* Date & Time row */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label className="text-sm font-medium flex items-center gap-1.5">
                  <CalendarDays className="w-3.5 h-3.5" />
                  {t("booking.form.date", "日期")} *
                </Label>
                <Select value={bookingDate} onValueChange={setBookingDate}>
                  <SelectTrigger>
                    <SelectValue placeholder={t("booking.form.selectDate", "选择日期")} />
                  </SelectTrigger>
                  <SelectContent>
                    {dateOptions.map((d) => (
                      <SelectItem key={d.value} value={d.value}>{d.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label className="text-sm font-medium flex items-center gap-1.5">
                  <Clock className="w-3.5 h-3.5" />
                  {t("booking.form.time", "时间")} *
                </Label>
                <Select value={bookingTime} onValueChange={setBookingTime}>
                  <SelectTrigger>
                    <SelectValue placeholder={t("booking.form.selectTime", "选择时间")} />
                  </SelectTrigger>
                  <SelectContent>
                    {TIME_SLOTS.map((t) => (
                      <SelectItem key={t} value={t}>{t}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Party Size */}
            <div className="space-y-1.5">
              <Label className="text-sm font-medium flex items-center gap-1.5">
                <Users className="w-3.5 h-3.5" />
                {t("booking.form.partySize", "人数")}
              </Label>
              <Select value={partySize} onValueChange={setPartySize}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {PARTY_SIZES.map((s) => (
                    <SelectItem key={s} value={String(s)}>
                      {s} {t("booking.people", "人")}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Phone & Email */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label className="text-sm font-medium flex items-center gap-1.5">
                  <Phone className="w-3.5 h-3.5" />
                  {t("booking.form.phone", "电话")}
                </Label>
                <Input
                  value={guestPhone}
                  onChange={(e) => setGuestPhone(e.target.value)}
                  placeholder={t("booking.form.phonePlaceholder", "联系电话")}
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-sm font-medium flex items-center gap-1.5">
                  <Mail className="w-3.5 h-3.5" />
                  {t("booking.form.email", "邮箱")}
                </Label>
                <Input
                  type="email"
                  value={guestEmail}
                  onChange={(e) => setGuestEmail(e.target.value)}
                  placeholder={t("booking.form.emailPlaceholder", "联系邮箱")}
                />
              </div>
            </div>

            {/* Special Requests */}
            <div className="space-y-1.5">
              <Label className="text-sm font-medium flex items-center gap-1.5">
                <MessageSquare className="w-3.5 h-3.5" />
                {t("booking.form.specialRequests", "特殊要求")}
              </Label>
              <Textarea
                value={specialRequests}
                onChange={(e) => setSpecialRequests(e.target.value)}
                placeholder={t("booking.form.specialRequestsPlaceholder", "如有特殊饮食需求或其他要求，请在此说明")}
                className="min-h-[72px]"
              />
            </div>

            {/* Submit Button */}
            <Button
              onClick={handleSubmit}
              disabled={submitting}
              className="w-full h-11 text-sm font-semibold"
            >
              {submitting ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin mr-2" />
                  {t("booking.form.submitting", "提交中...")}
                </>
              ) : (
                t("booking.form.submit", "确认预订")
              )}
            </Button>

            <p className="text-[11px] text-muted-foreground text-center">
              {t("booking.form.disclaimer", "提交后餐厅将审核您的预订，确认后将通知您")}
            </p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default BookingDialog;
